import React, { useState, useEffect } from 'react';
import { View, Text, Button, StyleSheet } from 'react-native';
import AsyncStorage from '@react-native-async-storage/async-storage';
import reactNativeBiometrics, { BiometryType } from 'react-native-biometrics';

const App = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [isBiometricAvailable, setIsBiometricAvailable] = useState(false);

  useEffect(() => {
    checkAuthenticationStatus();
    checkBiometricAvailability();
  }, []);

  const checkAuthenticationStatus = async () => {
    try {
      const value = await AsyncStorage.getItem('isAuthenticated');
      if (value === 'true') {
        setIsAuthenticated(true);
      }
    } catch (e) {
      console.error('Error retrieving authentication status', e);
    }
  };

  const checkBiometricAvailability = async () => {
    const { available, biometryType } = await reactNativeBiometrics.isSensorAvailable();
    setIsBiometricAvailable(available);
    if (available) {
      console.log('Biometric type:', biometryType === BiometryType.FaceID ? 'Face ID' : 'Fingerprint');
    }
  };

  const authenticateUser = async () => {
    try {
      const { success } = await reactNativeBiometrics.simplePrompt({
        promptMessage: 'Confirm fingerprint',
        fallbackPromptMessage: 'Use device password instead?',
        cancelText: 'Esc',
      });

      if (success) {
        await AsyncStorage.setItem('isAuthenticated', 'true');
        setIsAuthenticated(true);
      }
    } catch (e) {
      console.error('Biometric authentication failed', e);
    }
  };

  const handlePasswordFallback = () => {
    // Implement password fallback logic here
    alert('Enter your password to proceed');
  };

  if (isAuthenticated) {
    return (
      <View style={styles.container}>
        <Text>Welcome! You are authenticated.</Text>
      </View>
    );
  }

  return (
    <View style={styles.container}>
      {isBiometricAvailable ? (
        <Button title="Authenticate with Face ID/Fingerprint" onPress={authenticateUser} />
      ) : (
        <Button title="Authenticate with Password" onPress={handlePasswordFallback} />
      )}
    </View>
  );
};

const styles = StyleSheet.create({
  container: {
    flex: 1,
    justifyContent: 'center',
    alignItems: 'center',
  },
});

export default App;